    r.x = (nr.z < nr.x) ? nr.z : nr.x;
    r.y = (nr.w < nr.y) ? nr.w : nr.y;
    r.z = (nr.x < nr.z) ? nr.z : nr.x;
    r.w = (nr.y < nr.w) ? nr.w : nr.y;

    nr.x = r.x;
    nr.y = (r.z < r.y) ? r.z : r.y;
    nr.z = (r.y < r.z) ? r.z : r.y;
    nr.w = r.w;
    return nr;
