inline float4 getLowest(float4 a, float4 b) {
    a.x = (b.w > a.x) ? a.x : b.w;
    a.y = (b.z > a.y) ? a.y : b.z;
    a.z = (b.y > a.z) ? a.z : b.y;
    a.w = (b.x > a.w) ? a.w : b.x;
